const body = $input.first().json.body || $input.first().json;
const email = (body.email || '').trim().toLowerCase();
const name = (body.name || 'User').trim();
const purpose = body.purpose || 'verify';
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) { return [{ json: { valid: false, error: 'Invalid email address format', email, name, purpose } }]; }
const otp = Math.floor(100000 + Math.random() * 900000).toString();
const sessionId = 'OTP_' + Date.now() + '_' + Math.random().toString(36).substring(2, 8).toUpperCase();
const now = new Date();
const expiryTime = new Date(now.getTime() + 10 * 60 * 1000);
const purposeText = { login: 'log in to your account', signup: 'complete your registration', reset_password: 'reset your password', verify: 'verify your identity' }[purpose] || 'verify your identity';
return [{ json: { valid: true, email, name, purpose, purpose_text: purposeText, otp, session_id: sessionId, generated_at: now.toISOString(), expiry_time: expiryTime.toISOString(), expiry_minutes: 10, attempts: 0 } }];

const submission = $('Extract Submission').first().json;
const record = $input.first().json;
const submittedOtp = submission.submitted_otp;
const submittedEmail = submission.submitted_email;
const sessionId = submission.session_id;
const storedOtp = String(record['OTP Code'] || '').trim();
const storedEmail = String(record['Email'] || '').trim().toLowerCase();
const expiryTime = new Date(record['Expiry Time']);
const now = new Date();
const attempts = parseInt(record['Attempts'] || 0) + 1;
if (record['Status'] === 'Verified') { return [{ json: { verified: false, reason: 'ALREADY_USED', message: 'This OTP has already been used.', email: submittedEmail, session_id: sessionId, attempts } }]; }
if (now > expiryTime) { return [{ json: { verified: false, reason: 'EXPIRED', message: 'Your OTP has expired. Please request a new one.', email: submittedEmail, session_id: sessionId, attempts, expired_at: expiryTime.toISOString() } }]; }
if (attempts > 5) { return [{ json: { verified: false, reason: 'TOO_MANY_ATTEMPTS', message: 'Too many failed attempts. Please request a new OTP.', email: submittedEmail, session_id: sessionId, attempts } }]; }
if (submittedEmail !== storedEmail) { return [{ json: { verified: false, reason: 'EMAIL_MISMATCH', message: 'Email does not match this OTP session.', email: submittedEmail, session_id: sessionId, attempts } }]; }
if (submittedOtp !== storedOtp) { return [{ json: { verified: false, reason: 'WRONG_OTP', message: 'Incorrect OTP. Please try again.', email: submittedEmail, session_id: sessionId, attempts, remaining_attempts: Math.max(0, 5 - attempts) } }]; }
return [{ json: { verified: true, reason: 'SUCCESS', message: 'OTP verified successfully.', email: submittedEmail, session_id: sessionId, verified_at: now.toISOString(), attempts, token: 'VERIFIED_' + sessionId + '_' + Date.now() } }];
